161→            [PSObject[]]$data = @([PSCustomObject]@{ id = 1; name = 'test' })
162→            Write-Cache -Key 'test-data' -Data $data -CacheDir $script:TestCacheDir
163→
164→            [string]$expectedPath = Join-Path -Path $script:TestCacheDir -ChildPath 'test-data.json'
