171→
172→            [string]$filePath = Join-Path -Path $script:TestCacheDir -ChildPath 'json-check.json'
173→            [string]$content = Get-Content -Path $filePath -Raw -Encoding UTF8
174→            [PSObject[]]$parsed = $content | ConvertFrom-Json
