183→                [PSCustomObject]@{ id = 10; title = 'cached item' }
184→            )
185→            Write-Cache -Key 'read-test' -Data $original -CacheDir $script:TestCacheDir
186→            [PSObject[]]$result = Read-Cache -Key 'read-test' -CacheDir $script:TestCacheDir
187→
188→            $result | Should -Not -BeNullOrEmpty
