203→            Test-Path -Path $script:TestCacheDir | Should -BeTrue
204→
205→            Clear-Cache -CacheDir $script:TestCacheDir
206→            Test-Path -Path $script:TestCacheDir | Should -BeFalse
207→        }
208→    }
209→
210→    Context 'Round-trip with multiple items' {
211→        It 'Should preserve array structure through write/read cycle' {
212→            [PSObject[]]$data = @(
213→                [PSCustomObject]@{ id = 1; name = 'first' }
214→                [PSCustomObject]@{ id = 2; name = 'second' }
215→                [PSCustomObject]@{ id = 3; name = 'third' }
216→            )
217→            Write-Cache -Key 'roundtrip' -Data $data -CacheDir $script:TestCacheDir
218→            [PSObject[]]$result = Read-Cache -Key 'roundtrip' -CacheDir $script:TestCacheDir
219→
220→            $result.Count | Should -Be 3
221→            $result[1].name | Should -Be 'second'
222→        }
223→    }
224→}
