 36→# =============================================================================
 37→# TDD Round 1: Invoke-RestMethodWithRetry — retry with exponential backoff
 38→# RED:  Tests written first expecting retry behavior and error handling
 39→# GREEN: Implemented retry loop in module
 40→# =============================================================================
 41→Describe 'Invoke-RestMethodWithRetry' {
 42→
 43→    Context 'When the API call succeeds on the first attempt' {
 44→        BeforeAll {
 45→            # Mock the underlying Invoke-RestMethod to succeed immediately
 46→            Mock -ModuleName RestApiClient Invoke-RestMethod {
 47→                return @([PSCustomObject]@{ id = 1; title = 'Test' })
 48→            }
 49→        }
 50→
 51→        It 'Should return the API response' {
 52→            [PSObject[]]$result = Invoke-RestMethodWithRetry -Uri 'https://example.com/test'
 53→            $result.Count | Should -Be 1
 54→            $result[0].id | Should -Be 1
 55→        }
 56→
 57→        It 'Should call Invoke-RestMethod exactly once' {
 58→            Invoke-RestMethodWithRetry -Uri 'https://example.com/test' | Out-Null
 59→            Should -Invoke -ModuleName RestApiClient Invoke-RestMethod -Times 1 -Exactly -Scope It
 60→        }
 61→    }
 62→
 63→    Context 'When the API call fails then succeeds (transient failure)' {
 64→        BeforeAll {
 65→            [int]$script:retryCallCount = 0
 66→            Mock -ModuleName RestApiClient Invoke-RestMethod {
 67→                $script:retryCallCount++
 68→                if ($script:retryCallCount -le 2) {
 69→                    throw [System.Net.Http.HttpRequestException]::new('Connection refused')
 70→                }
 71→                return @([PSCustomObject]@{ id = 1; title = 'Recovered' })
 72→            }
 73→            # Mock Start-Sleep so tests run fast
 74→            Mock -ModuleName RestApiClient Start-Sleep {}
 75→        }
 76→
 77→        BeforeEach {
 78→            $script:retryCallCount = 0
 79→        }
 80→
 81→        It 'Should retry and eventually return the response' {
 82→            [PSObject[]]$result = Invoke-RestMethodWithRetry -Uri 'https://example.com/test' -MaxRetries 3 -BaseDelaySeconds 0.001
 83→            $result[0].title | Should -Be 'Recovered'
 84→        }
 85→
 86→        It 'Should have called Invoke-RestMethod multiple times' {
 87→            Invoke-RestMethodWithRetry -Uri 'https://example.com/test' -MaxRetries 3 -BaseDelaySeconds 0.001 | Out-Null
 88→            Should -Invoke -ModuleName RestApiClient Invoke-RestMethod -Times 3 -Exactly -Scope It
 89→        }
 90→    }
 91→
 92→    Context 'When all retry attempts are exhausted' {
 93→        BeforeAll {
 94→            Mock -ModuleName RestApiClient Invoke-RestMethod {
 95→                throw [System.Net.Http.HttpRequestException]::new('Server error 500')
 96→            }
 97→            Mock -ModuleName RestApiClient Start-Sleep {}
 98→        }
 99→
100→        It 'Should throw an error with a meaningful message after max retries' {
101→            { Invoke-RestMethodWithRetry -Uri 'https://example.com/fail' -MaxRetries 2 -BaseDelaySeconds 0.001 } |
102→                Should -Throw '*failed after 2 retries*'
103→        }
104→
105→        It 'Should have attempted the call MaxRetries + 1 times (initial + retries)' {
106→            try {
107→                Invoke-RestMethodWithRetry -Uri 'https://example.com/fail' -MaxRetries 2 -BaseDelaySeconds 0.001
108→            }
109→            catch {
110→                # expected
111→            }
112→            # 1 initial + 2 retries = 3 total calls
113→            Should -Invoke -ModuleName RestApiClient Invoke-RestMethod -Times 3 -Exactly -Scope It
114→        }
115→    }
116→
117→    Context 'Exponential backoff timing' {
118→        BeforeAll {
119→            Mock -ModuleName RestApiClient Invoke-RestMethod {
120→                throw [System.Net.Http.HttpRequestException]::new('Timeout')
121→            }
122→            Mock -ModuleName RestApiClient Start-Sleep {}
123→        }
124→
125→        It 'Should call Start-Sleep with exponentially increasing delays' {
126→            try {
127→                Invoke-RestMethodWithRetry -Uri 'https://example.com/slow' -MaxRetries 3 -BaseDelaySeconds 1.0
128→            }
129→            catch {
130→                # expected after exhausting retries
131→            }
132→            # Attempt 1 fails -> sleep 1s (1 * 2^0), attempt 2 fails -> sleep 2s (1 * 2^1),
133→            # attempt 3 fails -> sleep 4s (1 * 2^2), attempt 4 (last) fails -> throw
134→            Should -Invoke -ModuleName RestApiClient Start-Sleep -Times 1 -Scope It -ParameterFilter { $Milliseconds -eq 1000 }
135→            Should -Invoke -ModuleName RestApiClient Start-Sleep -Times 1 -Scope It -ParameterFilter { $Milliseconds -eq 2000 }
136→            Should -Invoke -ModuleName RestApiClient Start-Sleep -Times 1 -Scope It -ParameterFilter { $Milliseconds -eq 4000 }
137→        }
138→    }
139→}
